//ret /= vec3(0.4,2.9,2.7);
//ret /= vec3(1.8,1.2,2.3);
//MilkDrop3 Rainbow Mode:
ret *= 1*normalize((texture(sampler_noise_hq,(vUv+q4/2)/6)));

  fragColor = ret;
}
